+fn durability_policy() -> ObjectPlacementPolicy {
+    ObjectPlacementPolicy {
+        min_nodes: 2,
+        max_node_fraction_bps: 10_000,
+        preferred_devices: Vec::new(),
+        excluded_devices: Vec::new(),
+        target_coverage_bps: 10_000,
+        min_source_diversity: 2,
+    }
+}
