+fn default_repair_config() -> RepairControllerConfig {
+    RepairControllerConfig {
+        max_concurrent_repairs: 10,
+        max_repairs_per_minute: 100,
+        repair_interval: Duration::from_secs(60),
+        min_deficit_bps: 500,
+        max_symbols_per_repair: 100,
+    }
+}
